#!/usr/bin/env bun
/* eslint-disable @typescript-eslint/no-require-imports */
"use strict";

/**
 * Precheck invoked before `electron-builder` in `bun run build` /
 * `bun run build:dir`. Mirrors `check-cli-resource.cjs`: the packaged app
 * cannot ship without the tray icons listed below or it will surface as an
 * invisible system-tray entry on end-user machines (the failure mode the
 * placeholder `nativeImage.createEmpty()` previously produced).
 *
 * Files are generated by `scripts/generate-tray-icons.cjs` and committed to
 * the repo, so the only realistic way to hit this failure is an accidental
 * rename or delete. Fail loudly with a regeneration hint.
 */

const { existsSync, statSync } = require("node:fs");
const { resolve } = require("node:path");

const trayDir = resolve(__dirname, "..", "..", "resources", "tray");

// PNG signature bytes - `89 50 4E 47 0D 0A 1A 0A`. The asset directory also
// holds a README.md, so we explicitly verify each required PNG by name and
// peek at the first bytes to catch silent truncation / corruption.
const PNG_SIGNATURE = Buffer.from([
  0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a,
]);

const required = [
  "trayTemplate.png",
  "trayTemplate@2x.png",
  "tray.png",
  "tray@2x.png",
];

const problems = [];

for (const name of required) {
  const path = resolve(trayDir, name);
  if (!existsSync(path)) {
    problems.push(`missing: ${name}`);
    continue;
  }
  const info = statSync(path);
  if (!info.isFile() || info.size === 0) {
    problems.push(`empty or non-file: ${name}`);
    continue;
  }
  const fd = require("node:fs").openSync(path, "r");
  const head = Buffer.alloc(8);
  try {
    require("node:fs").readSync(fd, head, 0, 8, 0);
  } finally {
    require("node:fs").closeSync(fd);
  }
  if (!head.equals(PNG_SIGNATURE)) {
    problems.push(`not a valid PNG (bad signature): ${name}`);
  }
}

if (problems.length > 0) {
  console.error(
    `[desktop] tray asset precheck failed under ${trayDir}:\n` +
      problems.map((p) => `         - ${p}`).join("\n") +
      "\n\n" +
      "         The desktop build refuses to package without a real tray icon\n" +
      "         (the previous placeholder produced an invisible tray entry on\n" +
      "         end-user machines). Regenerate the assets via\n" +
      "         'bun clients/desktop/scripts/assets/generate-tray-icons.cjs'\n" +
      "         or restore the missing files from git.",
  );
  process.exit(1);
}

console.log(
  `[desktop] tray asset precheck ok - ${required.length} icon files present at ${trayDir}.`,
);
